const w = $('Loop Over Watchlist').item.json;
const first = $input.first();
const item = first ? first.json : {};
const has_baseline = !!(item && item.id !== undefined);
let baseline = null;
if (has_baseline) {
  let formats = {}; let known_hooks = [];
  try { formats = JSON.parse(item.formats_json || '{}'); } catch (e) {}
  try { known_hooks = JSON.parse(item.known_hooks_json || '[]'); } catch (e) {}
  baseline = {
    cadence: { tweets_per_day_mean: item.cadence_mean || 0, tweets_per_day_stdev: item.cadence_stdev || 0 },
    engagement: {
      likes: { mean: item.likes_mean || 0, stdev: item.likes_stdev || 0 },
      retweets: { mean: item.retweets_mean || 0, stdev: item.retweets_stdev || 0 },
      views: { mean: item.views_mean || 0, stdev: item.views_stdev || 0 }
    },
    formats, known_hooks
  };
}
return [{ json: { handle: w.handle, display_name: w.display_name, has_baseline, baseline } }];

const ctx = $('Normalize Baseline').item.json;
const tweets = $input.all().map(i => i.json).filter(t => t && !t.noResults);
const baseline = ctx.baseline;
const result = { handle: ctx.handle, display_name: ctx.display_name, has_baseline: ctx.has_baseline, tweet_count_today: tweets.length, viral_hits: [], cadence_anomaly: false, ambiguous_tweets: [], known_formats: [], known_hooks: [] };
if (ctx.has_baseline && baseline) {
  const likeMean = (baseline.engagement && baseline.engagement.likes && baseline.engagement.likes.mean) || 0;
  const likeStdev = (baseline.engagement && baseline.engagement.likes && baseline.engagement.likes.stdev) || 0;
  result.known_formats = Object.keys(baseline.formats || {});
  result.known_hooks = baseline.known_hooks || [];
  for (const t of tweets) {
    const likes = t.likeCount || t.favoriteCount || 0;
    const z = likeStdev > 0 ? (likes - likeMean) / likeStdev : 0;
    const multiple = likeMean > 0 ? likes / likeMean : 0;
    if (z > 2 || multiple > 5) {
      result.viral_hits.push({ id: t.id, url: t.url || t.twitterUrl, text: (t.text || '').slice(0, 280), likes, z: Math.round(z * 100) / 100, multiple: Math.round(multiple * 100) / 100 });
    }
    if (!t.isRetweet && !t.isReply) {
      result.ambiguous_tweets.push({ id: t.id, text: (t.text || '').slice(0, 500) });
    }
  }
  const meanPerDay = (baseline.cadence && baseline.cadence.tweets_per_day_mean) || 0;
  const stdevPerDay = (baseline.cadence && baseline.cadence.tweets_per_day_stdev) || 0;
  if (stdevPerDay > 0 && Math.abs(tweets.length - meanPerDay) / stdevPerDay > 2) { result.cadence_anomaly = true; }
}
return [{ json: result }];

const ctx = $('Detect Outliers').item.json;
let verdicts = [];
try {
  const content = $json.choices[0].message.content;
  const parsed = JSON.parse(content);
  verdicts = parsed.verdicts || [];
} catch (e) { verdicts = []; }
return [{ json: Object.assign({}, ctx, { new_format_flags: verdicts.filter(v => v.is_new_format) }) }];

const agg = $input.first().json;
const rows = [];
for (const a of agg.alerts) {
  if (a.error) { rows.push({ run_date: agg.run_date, handle: a.handle, alert_type: 'error', detail: a.error, metric: '', tweet_url: '' }); continue; }
  if (!a.has_baseline) { rows.push({ run_date: agg.run_date, handle: a.handle, alert_type: 'no_baseline', detail: 'No baseline yet -- run X Deep Scan for this handle', metric: '', tweet_url: '' }); continue; }
  let any = false;
  for (const v of (a.viral_hits || [])) { any = true; rows.push({ run_date: agg.run_date, handle: a.handle, alert_type: 'viral_hit', detail: v.text, metric: v.likes + ' likes (' + v.multiple + 'x avg)', tweet_url: v.url || '' }); }
  if (a.cadence_anomaly) { any = true; rows.push({ run_date: agg.run_date, handle: a.handle, alert_type: 'cadence_anomaly', detail: 'Posted ' + a.tweet_count_today + ' today, off from baseline', metric: '', tweet_url: '' }); }
  for (const f of (a.new_format_flags || [])) { any = true; rows.push({ run_date: agg.run_date, handle: a.handle, alert_type: 'new_format', detail: (f.label || '') + ': ' + (f.rationale || ''), metric: '', tweet_url: '' }); }
  if (!any) { rows.push({ run_date: agg.run_date, handle: a.handle, alert_type: 'ok', detail: 'Nothing unusual (' + a.tweet_count_today + ' tweet(s) today)', metric: '', tweet_url: '' }); }
}
return rows.map(r => ({ json: r }));
